<script>
    const planData = { premium: { name: 'Premium', roi: .0204, days: 60 }, silver: { name: 'Silver', roi: .0103, days: 90 }, gold: { name: 'Gold', roi: .0039, days: 180 }, star: { name: 'Star', roi: .0029, days: 365 }, unlimited: { name: 'Unlimited', roi: .0019, days: 365 } };
    function fmt(n) { return '$' + n.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) }
    function doCalc() { const pk = document.getElementById('plan-sel').value; const amt = parseFloat(document.getElementById('inv-amt').value); if (!amt || amt <= 0) { alert('Enter a valid investment amount.'); return } const p = planData[pk]; const profit = amt * p.roi * p.days; document.getElementById('r1').textContent = fmt(amt); document.getElementById('r2').textContent = p.name; document.getElementById('r3').textContent = (p.roi * 100).toFixed(2) + '%'; document.getElementById('r4').textContent = p.days + ' days'; document.getElementById('r5').textContent = fmt(profit); document.getElementById('r6').textContent = fmt(amt + profit); }
</script>